Find the bug(s) in the following code and explain the fix:

```javascript
const EventEmitter = require('events')
const emitter = new EventEmitter()
emitter.setMaxListeners(0) // Allow unlimited listeners

function handleConnection(socket) {
  const onBroadcast = (msg) => {
    socket.write(msg)
  }

  emitter.on('broadcast', onBroadcast)

  socket.on('close', () => {
    console.log('Connection closed')
    // Cleanup: close handling
    socket.destroy()
  })

  socket.on('error', (err) => {
    console.error('Socket error:', err.message)
  })
}

// Called for every new TCP connection
server.on('connection', (socket) => {
  handleConnection(socket)
})
```
